        tokens.add(new Token(Token.TokenTypes.IDENTIFIER,3,13,"Print"));
        tokens.add(new Token(Token.TokenTypes.WITH,3,18));
        tokens.add(new Token(Token.TokenTypes.STRINGLITERAL,3,22,"4"));
