        tokens.add(new Token(Token.TokenTypes.CHARACTERLITERAL,4,7,"a"));
        tokens.add(new Token(Token.TokenTypes.DOUBLEEQUAL,4,10));
        tokens.add(new Token(Token.TokenTypes.CHARACTERLITERAL,4,11,"A"));
        tokens.add(new Token(Token.TokenTypes.OR,4,14));
        tokens.add(new Token(Token.TokenTypes.STRINGLITERAL,4,22,"Hello"));
        tokens.add(new Token(Token.TokenTypes.NOTEQUAL,4,25));
        tokens.add(new Token(Token.TokenTypes.STRINGLITERAL,4,33,"World"));
        tokens.add(new Token(Token.TokenTypes.NEWLINE,5,0));
        tokens.add(new Token(Token.TokenTypes.INDENT,5,8));
        tokens.add(new Token(Token.TokenTypes.SET,5,11));
        tokens.add(new Token(Token.TokenTypes.IDENTIFIER,5,19,"boolVar"));
        tokens.add(new Token(Token.TokenTypes.TO,5,22));
        tokens.add(new Token(Token.TokenTypes.TRUE,5,27));
        tokens.add(new Token(Token.TokenTypes.NEWLINE,6,0));
        tokens.add(new Token(Token.TokenTypes.DEDENT,6,0));
        tokens.add(new Token(Token.TokenTypes.DEDENT,6,0));
        tokens.add(new Token(Token.TokenTypes.NEWLINE,6,0));
        var ast = new PlainEnglishParser(tokens).program().orElseThrow();
        Assertions.assertEquals("SimpleIf",ast.method.get(0).name);
        Assertions.assertFalse(ast.method.get(0).with);
        Assertions.assertTrue(ast.method.get(0).className.isEmpty());
        Assertions.assertTrue(ast.method.get(0).statementblock.statement.get(0).$if.isPresent());
        Assertions.assertFalse(ast.method.get(0).statementblock.statement.get(0).$if.get().boolexpterm.not);
        Assertions.assertFalse(ast.method.get(0).statementblock.statement.get(0).$if.get().boolexpterm.boolexpfactor.get().lhs.get().term.get(0).factor.get(0).$true);
        Assertions.assertFalse(ast.method.get(0).statementblock.statement.get(0).$if.get().boolexpterm.boolexpfactor.get().lhs.get().term.get(0).factor.get(0).$false);
        Assertions.assertEquals("4",ast.method.get(0).statementblock.statement.get(0).$if.get().boolexpterm.boolexpfactor.get().lhs.get().term.get(0).factor.get(0).number.get());
        Assertions.assertFalse(ast.method.get(0).statementblock.statement.get(0).$if.get().boolexpterm.boolexpfactor.get().rhs.get().term.get(0).factor.get(0).$true);
        Assertions.assertFalse(ast.method.get(0).statementblock.statement.get(0).$if.get().boolexpterm.boolexpfactor.get().rhs.get().term.get(0).factor.get(0).$false);
        Assertions.assertEquals("7",ast.method.get(0).statementblock.statement.get(0).$if.get().boolexpterm.boolexpfactor.get().rhs.get().term.get(0).factor.get(0).number.get());
        Assertions.assertEquals(PlainEnglish.AST.compareOps.lessthan,ast.method.get(0).statementblock.statement.get(0).$if.get().boolexpterm.boolexpfactor.get().thecompareOps.get());
        Assertions.assertTrue(ast.method.get(0).statementblock.statement.get(0).$if.get().statementblock.statement.get(0).functioncall.isPresent());
        Assertions.assertEquals("Print",ast.method.get(0).statementblock.statement.get(0).$if.get().statementblock.statement.get(0).functioncall.get().name);
