        Assertions.assertFalse(ast.method.get(0).statementblock.statement.get(1).$if.get().boolexpterm.not);
        Assertions.assertEquals("or",ast.method.get(0).statementblock.statement.get(1).$if.get().boolexpterm.theandORor.get(0).toString());
