        Assertions.assertEquals("Hello",ast.method.get(0).statementblock.statement.get(1).$if.get().boolexpterm.boolexpterm.get(0).boolexpfactor.get().lhs.get().term.get(0).factor.get(0).stringliteral.get());
        Assertions.assertFalse(ast.method.get(0).statementblock.statement.get(1).$if.get().boolexpterm.boolexpterm.get(0).boolexpfactor.get().rhs.get().term.get(0).factor.get(0).$true);
