        Assertions.assertFalse(ast.method.get(0).statementblock.statement.get(1).$if.get().boolexpterm.boolexpfactor.get().lhs.get().term.get(0).factor.get(0).$false);
        Assertions.assertEquals("a",ast.method.get(0).statementblock.statement.get(1).$if.get().boolexpterm.boolexpfactor.get().lhs.get().term.get(0).factor.get(0).characterliteral.get());
