        Assertions.assertTrue(ast.method.get(0).statementblock.statement.get(1).$if.get().statementblock.statement.get(0).set.isPresent());
        Assertions.assertEquals("boolVar",ast.method.get(0).statementblock.statement.get(1).$if.get().statementblock.statement.get(0).set.get().variablereference.name);
        Assertions.assertEquals(false,ast.method.get(0).statementblock.statement.get(1).$if.get().statementblock.statement.get(0).set.get().variablereference.of);
        Assertions.assertFalse(ast.method.get(0).statementblock.statement.get(1).$if.get().statementblock.statement.get(0).set.get().variablereference.$object.isPresent());
