                "    If numVar % 2 == 0\n" +
                "        Print with \"Even\"\n" +
                "    Else\n" +
                "        Print with \"Odd\"\n" +
                "";

        var tokens = new LinkedList<Token>();
        tokens.add(new Token(Token.TokenTypes.TO,1,2));
        tokens.add(new Token(Token.TokenTypes.IDENTIFIER,1,9,"IfElse"));
        tokens.add(new Token(Token.TokenTypes.NEWLINE,2,0));
