        Assertions.assertFalse(ast.method.get(0).statementblock.statement.get(0).$if.get().boolexpterm.boolexpfactor.get().lhs.get().term.get(0).factor.get(0).$false);
        Assertions.assertEquals("numVar",ast.method.get(0).statementblock.statement.get(0).$if.get().boolexpterm.boolexpfactor.get().lhs.get().term.get(0).factor.get(0).variablereference.get().name);
